#!/usr/bin/env node
// Wrap a dist compiler bundle into a browser IIFE (demo/compiler.*.js)
// Run: node tools/build_browser_bundle.js --input dist/compiler.bootstrap.js ...

const fs   = require('fs')
const path = require('path')

const ROOT   = path.join(__dirname, '..')
const STDLIB = path.join(ROOT, 'demo', 'synth.stdlib.js')

function parseArgs(argv) {
  let input  = path.join(ROOT, 'dist', 'compiler.synth.js')
  let out    = path.join(ROOT, 'demo', 'compiler.synth.js')
  let backend = 'synth'
  let version = '1.0.0-selfhost'
  let force = false

  for (let i = 0; i < argv.length; i++) {
    if (argv[i] === '--input' && argv[i + 1]) input = path.resolve(argv[++i])
    else if (argv[i] === '--out' && argv[i + 1]) out = path.resolve(argv[++i])
    else if (argv[i] === '--backend' && argv[i + 1]) backend = argv[++i]
    else if (argv[i] === '--version' && argv[i + 1]) version = argv[++i]
    else if (argv[i] === '--force') force = true
  }
  return { input, out, backend, version, force }
}

function buildBundle({ input, out, backend, version }) {
  if (!fs.existsSync(input)) {
    throw new Error(`missing compiler bundle: ${input}`)
  }
  if (!fs.existsSync(STDLIB)) {
    throw new Error(`missing stdlib: ${STDLIB}`)
  }

  const compilerBody = fs.readFileSync(input, 'utf8')
  const stdlibRaw = fs.readFileSync(STDLIB, 'utf8')
  const stdlibContent = '\n' + stdlibRaw.replace(/^(\/\/[^\n]*\n)+/, '')
  const inputBase = path.basename(input)

  const bundle = `// Synth compiler — browser bundle
// Generated by tools/build_browser_bundle.js — do not edit
// Source: ${inputBase}
// API: SynthCompiler.compile(src) → { js, errors, warnings }
//      SynthCompiler.check(src)   → { warnings, errors }
//      SynthCompiler.stdlib       → stdlib JS string
//      SynthCompiler.version      → "${version}"
//      SynthCompiler.backend      → "${backend}"
(function (global) {
  "use strict";

  const SYNTH_STDLIB = ${JSON.stringify(stdlibContent)};

  const __synth_compiler = (function () {
${compilerBody}
    return { compile, check_source, tokenize, parse, generate, check };
  })();

  function formatWarnings(diags) {
    return (diags || []).map(d => ({
      severity: d.severity || 'warning',
      message:  d.message,
      line:     d.line ?? 1,
      col:      d.col ?? 1,
    }))
  }

  function validateJs(js) {
    if (!js) return null
    try {
      new Function(js)
      return null
    } catch (e) {
      return String(e.message || e)
    }
  }

  function compile(source) {
    try {
      const result = __synth_compiler.compile(source)
      const syntaxErr = validateJs(result.js)
      if (syntaxErr) {
        return {
          js: null,
          errors: [{ message: 'Codegen produced invalid JavaScript: ' + syntaxErr, line: 1, col: 1, kind: 'codegen' }],
          warnings: formatWarnings(result.warnings),
        }
      }
      return {
        js: result.js,
        errors: [],
        warnings: formatWarnings(result.warnings),
      }
    } catch (e) {
      return {
        js: null,
        errors: [{ message: String(e), line: 1, col: 1, kind: 'error' }],
        warnings: [],
      }
    }
  }

  function check(source) {
    try {
      const warnings = __synth_compiler.check_source(source)
      return { warnings: formatWarnings(warnings), errors: [] }
    } catch (e) {
      return {
        warnings: [],
        errors: [{ message: String(e), line: 1, col: 1 }],
      }
    }
  }

  global.SynthCompiler = {
    compile,
    check,
    version: '${version}',
    backend: '${backend}',
    stdlib: SYNTH_STDLIB,
  }

})(typeof window !== 'undefined' ? window : typeof globalThis !== 'undefined' ? globalThis : this);
`

  fs.writeFileSync(out, bundle, 'utf8')
  return { lines: bundle.split('\n').length, out }
}

function isFresh(output, inputs) {
  if (!fs.existsSync(output)) return false
  const outMtime = fs.statSync(output).mtimeMs
  return inputs.every(f => fs.existsSync(f) && fs.statSync(f).mtimeMs <= outMtime)
}

function main() {
  const opts = parseArgs(process.argv.slice(2))
  const inputs = [opts.input, STDLIB, __filename]

  if (!opts.force && isFresh(opts.out, inputs)) {
    console.log(`✓ ${path.basename(opts.out)} up to date (use --force to rebuild)`)
    return
  }

  const info = buildBundle(opts)
  console.log(`✓ ${path.basename(opts.out)}  ${info.lines} lines  ←  ${path.basename(opts.input)}`)
}

main()
